# ============================================================================
# tests/performance_benchmark_test.fl - Performance Benchmarks (Week 3 Day 4-5)
# ============================================================================
# 작성: 2026-03-02
# 목표: Phase 3 성능 벤치마크 + 병목 지점 식별
# 범위: 5개 벤치마크 × 3가지 규모 (small, medium, large)
#
# 벤치마크 규모:
# - Small: 100 vectors, 5-node cluster
# - Medium: 1,000 vectors, 5-node cluster
# - Large: 10,000 vectors, 7-node cluster

# ============================================================================
# Test Group 1: Vector Insert Benchmarks
# ============================================================================

fn testInsertPerformanceSmall() -> Result<map<string, number>, string>
  # Arrange: Small dataset
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Act: Insert 100 vectors
  let benchmark = benchmarkVectorInsert(cluster, coordinator, 100, 128)

  # Assert: Check baseline metrics
  match validate(benchmark)
    Ok(_) ->
      Ok({
        "throughput": benchmark["throughput"],
        "avgLatencyMs": benchmark["avgLatencyMs"],
        "p99LatencyMs": benchmark["p99LatencyMs"],
        "memoryPerVectorKb": benchmark["memoryPerVectorKb"]
      })
    Err(e) ->
      Err("Small insert benchmark failed: " + e)

fn testInsertPerformanceMedium() -> Result<map<string, number>, string>
  # Arrange: Medium dataset
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Act: Insert 1000 vectors
  let benchmark = benchmarkVectorInsert(cluster, coordinator, 1000, 128)

  # Assert: Validate performance under load
  if benchmark["totalOperations"] >= 900
    Ok({
      "throughput": benchmark["throughput"],
      "avgLatencyMs": benchmark["avgLatencyMs"],
      "p99LatencyMs": benchmark["p99LatencyMs"],
      "successRate": number(benchmark["totalOperations"]) / 1000.0
    })
  else
    Err("Medium insert: too many failures")

fn testInsertPerformanceLarge() -> Result<map<string, number>, string>
  # Arrange: Large dataset
  let cluster = createBenchmarkCluster(7)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Act: Insert 10000 vectors
  let benchmark = benchmarkVectorInsert(cluster, coordinator, 10000, 256)

  # Assert: Verify scalability
  if benchmark["totalOperations"] >= 9500
    Ok({
      "throughput": benchmark["throughput"],
      "totalTimeS": benchmark["totalTimeMs"] / 1000.0,
      "successRate": number(benchmark["totalOperations"]) / 10000.0,
      "memoryEstimateMb": benchmark["memoryPerVectorKb"] * 10000.0 / 1024.0
    })
  else
    Err("Large insert: insufficient success rate")

fn testInsertThroughputScaling() -> Result<bool, string>
  # Test: Throughput should increase with cluster size
  let cluster5 = createBenchmarkCluster(5)
  let coordinator5 = createBenchmarkCoordinator(cluster5)
  let bench5 = benchmarkVectorInsert(cluster5, coordinator5, 500, 128)

  let cluster7 = createBenchmarkCluster(7)
  let coordinator7 = createBenchmarkCoordinator(cluster7)
  let bench7 = benchmarkVectorInsert(cluster7, coordinator7, 500, 128)

  # 7-node cluster should have better throughput than 5-node
  if bench7["throughput"] >= bench5["throughput"] * 0.8
    Ok(true)
  else
    Err("Scaling: 7-node throughput not better than 5-node")

# ============================================================================
# Test Group 2: Vector Search Benchmarks
# ============================================================================

fn testSearchPerformanceSmall() -> Result<map<string, number>, string>
  # Arrange: Insert data then search
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Insert baseline vectors
  benchmarkVectorInsert(cluster, coordinator, 100, 128)

  # Act: Search with small query set
  let benchmark = benchmarkVectorSearch(cluster, coordinator, 50, 128, 10)

  # Assert
  if benchmark["successfulSearches"] >= 45
    Ok({
      "throughput": benchmark["throughput"],
      "avgLatencyMs": benchmark["avgLatencyMs"],
      "p99LatencyMs": benchmark["p99LatencyMs"],
      "avgRecall": benchmark["avgRecall"]
    })
  else
    Err("Small search: insufficient success rate")

fn testSearchPerformanceMedium() -> Result<map<string, number>, string>
  # Arrange
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 1000, 128)

  # Act: 500 queries on 1000 vectors
  let benchmark = benchmarkVectorSearch(cluster, coordinator, 500, 128, 10)

  # Assert
  if benchmark["successfulSearches"] >= 450
    Ok({
      "throughput": benchmark["throughput"],
      "avgLatencyMs": benchmark["avgLatencyMs"],
      "p99LatencyMs": benchmark["p99LatencyMs"],
      "avgRecall": benchmark["avgRecall"],
      "successRate": number(benchmark["successfulSearches"]) / 500.0
    })
  else
    Err("Medium search: insufficient success rate")

fn testSearchAccuracy() -> Result<bool, string>
  # Arrange: Verify search returns correct results
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 200, 64)

  # Act: Execute benchmark searches
  let benchmark = benchmarkVectorSearch(cluster, coordinator, 100, 64, 5)

  # Assert: Recall should be high
  if benchmark["avgRecall"] >= 0.8
    Ok(true)
  else
    Err("Search accuracy low: recall = " + toString(benchmark["avgRecall"]))

fn testSearchLatencyDistribution() -> Result<bool, string>
  # Test: P99 should not be much worse than P50
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 500, 128)

  let benchmark = benchmarkVectorSearch(cluster, coordinator, 200, 128, 10)

  # P99 should be within 10x of P50
  let ratio = benchmark["p99LatencyMs"] / benchmarkMaxOfTwoNumbers(benchmark["p50LatencyMs"], 0.1)
  if ratio <= 10.0
    Ok(true)
  else
    Err("Latency distribution skewed: P99/P50 = " + toString(ratio))

# ============================================================================
# Test Group 3: Failover Performance Benchmarks
# ============================================================================

fn testFailoverRecoverySpeed() -> Result<map<string, number>, string>
  # Arrange
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Act: Execute multiple failovers
  let benchmark = benchmarkFailover(cluster, coordinator, 5)

  # Assert: Recovery time should be within 150-200ms
  if benchmark["avgLeaderElectionTimeMs"] <= 200.0
    Ok({
      "avgElectionTimeMs": benchmark["avgLeaderElectionTimeMs"],
      "p99ElectionTimeMs": benchmark["p99ElectionTimeMs"],
      "successRate": benchmark["failoverSuccessRate"]
    })
  else
    Err("Failover too slow: " + toString(benchmark["avgLeaderElectionTimeMs"]) + "ms")

fn testFailoverDataDurability() -> Result<bool, string>
  # Test: No data loss during failover
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  # Insert critical data
  benchmarkVectorInsert(cluster, coordinator, 100, 128)

  # Trigger failovers
  let benchmark = benchmarkFailover(cluster, coordinator, 3)

  # Assert: Zero data loss
  if benchmark["dataLossCount"] == 0
    Ok(true)
  else
    Err("Data loss detected during failover")

fn testFailoverSuccessRate() -> Result<bool, string>
  # Test: Failovers should succeed consistently
  let cluster = createBenchmarkCluster(7)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkFailover(cluster, coordinator, 10)

  # Success rate should be > 90%
  if benchmark["failoverSuccessRate"] >= 0.9
    Ok(true)
  else
    Err("Failover success rate too low: " + toString(benchmark["failoverSuccessRate"]))

fn testFailoverWriteResume() -> Result<bool, string>
  # Test: Writes should resume quickly after failover
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkFailover(cluster, coordinator, 5)

  # Write resume should be < 150ms
  if benchmark["writeResumeTimeMs"] <= 150.0
    Ok(true)
  else
    Err("Write resume time exceeded: " + toString(benchmark["writeResumeTimeMs"]) + "ms")

# ============================================================================
# Test Group 4: New Node Recovery Benchmarks
# ============================================================================

fn testNewNodeRecoverySpeed() -> Result<map<string, number>, string>
  # Arrange
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 1000, 128)

  # Act: Add 3 new nodes
  let benchmark = benchmarkNewNodeRecovery(cluster, coordinator, 3, 1000)

  # Assert: Recovery < 1000ms
  if benchmark["avgRecoveryTimeMs"] <= 1000.0
    Ok({
      "avgRecoveryTimeMs": benchmark["avgRecoveryTimeMs"],
      "maxRecoveryTimeMs": benchmark["maxRecoveryTimeMs"],
      "successfulJoins": benchmark["successfulJoins"]
    })
  else
    Err("Recovery too slow: " + toString(benchmark["avgRecoveryTimeMs"]) + "ms")

fn testNewNodeMemoryEfficiency() -> Result<bool, string>
  # Test: Snapshot recovery should use much less memory than full log
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 5000, 128)

  let benchmark = benchmarkNewNodeRecovery(cluster, coordinator, 2, 5000)

  # Memory per node should be ~5MB for 5000 vectors
  let expectedMemory = 5.0  # MB (rough estimate)
  if benchmark["memoryPerNodeMb"] <= expectedMemory * 2.0
    Ok(true)
  else
    Err("Recovery memory too high: " + toString(benchmark["memoryPerNodeMb"]) + "MB")

fn testNewNodeSearchReadiness() -> Result<bool, string>
  # Test: New nodes should be search-ready immediately
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 500, 128)

  let benchmark = benchmarkNewNodeRecovery(cluster, coordinator, 3, 500)

  # All successful joins should have search ready
  if benchmark["searchReadyCount"] == benchmark["successfulJoins"]
    Ok(true)
  else
    Err("Not all nodes search-ready")

fn testNewNodeWriteParticipation() -> Result<bool, string>
  # Test: New nodes should participate in replication
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkNewNodeRecovery(cluster, coordinator, 3, 1000)

  # All successful joins should have write capability
  if benchmark["writeReadyCount"] == benchmark["successfulJoins"]
    Ok(true)
  else
    Err("Not all nodes write-capable")

# ============================================================================
# Test Group 5: Network Partition Benchmarks
# ============================================================================

fn testPartitionMajorityAvailability() -> Result<map<string, number>, string>
  # Arrange
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  benchmarkVectorInsert(cluster, coordinator, 500, 128)

  # Act: Simulate partitions
  let benchmark = benchmarkNetworkPartition(cluster, coordinator, 5)

  # Assert: Majority should be available >= 95% of time
  if benchmark["majorityAvailabilityPercent"] >= 95.0
    Ok({
      "majorityAvailabilityPercent": benchmark["majorityAvailabilityPercent"],
      "dataConsistencyScore": benchmark["dataConsistencyScore"]
    })
  else
    Err("Majority availability too low")

fn testPartitionMinorityIsolation() -> Result<bool, string>
  # Test: Minority should be isolated from writes
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkNetworkPartition(cluster, coordinator, 5)

  # Minority data loss should be 0 (no successful writes)
  if benchmark["minorityDataLossCount"] == 0
    Ok(true)
  else
    Err("Minority was not isolated")

fn testPartitionHealingTime() -> Result<bool, string>
  # Test: Partition healing should be fast
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkNetworkPartition(cluster, coordinator, 3)

  # Healing < 1 second
  if benchmark["healingTimeMs"] <= 1000.0
    Ok(true)
  else
    Err("Partition healing time exceeded: " + toString(benchmark["healingTimeMs"]) + "ms")

fn testPartitionDataConsistency() -> Result<bool, string>
  # Test: After healing, all data should be consistent
  let cluster = createBenchmarkCluster(5)
  let coordinator = createBenchmarkCoordinator(cluster)

  let benchmark = benchmarkNetworkPartition(cluster, coordinator, 5)

  # Consistency score should be perfect (1.0)
  if benchmark["dataConsistencyScore"] >= 0.95
    Ok(true)
  else
    Err("Data consistency compromised: " + toString(benchmark["dataConsistencyScore"]))

fn testPartitionScalability() -> Result<bool, string>
  # Test: Larger cluster should handle partitions better
  let cluster7 = createBenchmarkCluster(7)
  let coordinator7 = createBenchmarkCoordinator(cluster7)

  let bench7 = benchmarkNetworkPartition(cluster7, coordinator7, 3)

  # 7-node cluster majority (4 nodes) should have even better availability
  if bench7["majorityAvailabilityPercent"] >= 95.0
    Ok(true)
  else
    Err("7-node partition handling worse than expected")

# ============================================================================
# Helper Functions
# ============================================================================

fn createBenchmarkCluster(nodeCount: number) -> map<string, any>
  let nodes = {}
  for i in range(0, nodeCount)
    nodes[toString(i)] = {
      "id": i,
      "state": if i == 0 then "LEADER" else "FOLLOWER",
      "currentTerm": 1,
      "log": array<map<string, any>>(),
      "commitIndex": 0,
      "lastApplied": 0,
      "lastSnapshotIndex": 0,
      "alive": true,
      "hybridIndex": {}
    }

  {
    "nodeIds": range(0, nodeCount),
    "nodes": nodes,
    "leaderElectionMs": 150
  }

fn createBenchmarkCoordinator(cluster: map<string, any>) -> map<string, any>
  {
    "nodeId": 0,
    "partitionCount": 16,
    "consistentHash": {
      "partitions": 16,
      "vnodes": 150
    },
    "cluster": cluster
  }

fn validate(benchmark: map<string, any>) -> Result<bool, string>
  if benchmark["totalOperations"] > 0
    Ok(true)
  else
    Err("No successful operations")

fn toString(x: any) -> string
  ""

fn length(arr: any) -> number
  0

fn range(start: number, end: number) -> array<number>
  array<number>()

fn push(arr: array<any>, item: any) -> array<any>
  arr

fn benchmarkMaxOfTwoNumbers(a: number, b: number) -> number
  if a > b then a else b

# ============================================================================
# Benchmark Test Runner
# ============================================================================

fn runAllPerformanceBenchmarks() -> Result<map<string, any>, string>
  let results = {
    "insertTests": array<string>(),
    "searchTests": array<string>(),
    "failoverTests": array<string>(),
    "newNodeTests": array<string>(),
    "partitionTests": array<string>(),
    "totalPassed": 0,
    "totalFailed": 0
  }

  # Insert benchmarks (4 tests)
  match testInsertPerformanceSmall()
    Ok(_) -> { results["insertTests"] = push(results["insertTests"], "SMALL"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["insertTests"] = push(results["insertTests"], "SMALL FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testInsertPerformanceMedium()
    Ok(_) -> { results["insertTests"] = push(results["insertTests"], "MEDIUM"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["insertTests"] = push(results["insertTests"], "MEDIUM FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testInsertPerformanceLarge()
    Ok(_) -> { results["insertTests"] = push(results["insertTests"], "LARGE"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["insertTests"] = push(results["insertTests"], "LARGE FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testInsertThroughputScaling()
    Ok(_) -> { results["insertTests"] = push(results["insertTests"], "SCALING"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["insertTests"] = push(results["insertTests"], "SCALING FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  # Search benchmarks (4 tests)
  match testSearchPerformanceSmall()
    Ok(_) -> { results["searchTests"] = push(results["searchTests"], "SMALL"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["searchTests"] = push(results["searchTests"], "SMALL FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testSearchPerformanceMedium()
    Ok(_) -> { results["searchTests"] = push(results["searchTests"], "MEDIUM"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["searchTests"] = push(results["searchTests"], "MEDIUM FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testSearchAccuracy()
    Ok(_) -> { results["searchTests"] = push(results["searchTests"], "ACCURACY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["searchTests"] = push(results["searchTests"], "ACCURACY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testSearchLatencyDistribution()
    Ok(_) -> { results["searchTests"] = push(results["searchTests"], "LATENCY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["searchTests"] = push(results["searchTests"], "LATENCY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  # Failover benchmarks (4 tests)
  match testFailoverRecoverySpeed()
    Ok(_) -> { results["failoverTests"] = push(results["failoverTests"], "SPEED"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["failoverTests"] = push(results["failoverTests"], "SPEED FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testFailoverDataDurability()
    Ok(_) -> { results["failoverTests"] = push(results["failoverTests"], "DURABILITY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["failoverTests"] = push(results["failoverTests"], "DURABILITY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testFailoverSuccessRate()
    Ok(_) -> { results["failoverTests"] = push(results["failoverTests"], "SUCCESS"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["failoverTests"] = push(results["failoverTests"], "SUCCESS FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testFailoverWriteResume()
    Ok(_) -> { results["failoverTests"] = push(results["failoverTests"], "WRITE_RESUME"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["failoverTests"] = push(results["failoverTests"], "WRITE_RESUME FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  # New Node benchmarks (4 tests)
  match testNewNodeRecoverySpeed()
    Ok(_) -> { results["newNodeTests"] = push(results["newNodeTests"], "SPEED"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["newNodeTests"] = push(results["newNodeTests"], "SPEED FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testNewNodeMemoryEfficiency()
    Ok(_) -> { results["newNodeTests"] = push(results["newNodeTests"], "MEMORY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["newNodeTests"] = push(results["newNodeTests"], "MEMORY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testNewNodeSearchReadiness()
    Ok(_) -> { results["newNodeTests"] = push(results["newNodeTests"], "SEARCH"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["newNodeTests"] = push(results["newNodeTests"], "SEARCH FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testNewNodeWriteParticipation()
    Ok(_) -> { results["newNodeTests"] = push(results["newNodeTests"], "WRITE"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["newNodeTests"] = push(results["newNodeTests"], "WRITE FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  # Partition benchmarks (5 tests)
  match testPartitionMajorityAvailability()
    Ok(_) -> { results["partitionTests"] = push(results["partitionTests"], "MAJORITY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["partitionTests"] = push(results["partitionTests"], "MAJORITY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testPartitionMinorityIsolation()
    Ok(_) -> { results["partitionTests"] = push(results["partitionTests"], "MINORITY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["partitionTests"] = push(results["partitionTests"], "MINORITY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testPartitionHealingTime()
    Ok(_) -> { results["partitionTests"] = push(results["partitionTests"], "HEALING"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["partitionTests"] = push(results["partitionTests"], "HEALING FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testPartitionDataConsistency()
    Ok(_) -> { results["partitionTests"] = push(results["partitionTests"], "CONSISTENCY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["partitionTests"] = push(results["partitionTests"], "CONSISTENCY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  match testPartitionScalability()
    Ok(_) -> { results["partitionTests"] = push(results["partitionTests"], "SCALABILITY"); results["totalPassed"] = results["totalPassed"] + 1 }
    Err(e) -> { results["partitionTests"] = push(results["partitionTests"], "SCALABILITY FAILED"); results["totalFailed"] = results["totalFailed"] + 1 }

  Ok(results)

