  // Handshake Type: Server Hello (2)
  message.append(2)
  // Version (same as client)
  message.append((tlsVersion >> 8) & 0xFF)
  message.append(tlsVersion & 0xFF)
  // Random (32 bytes)
  for i = 0 to 32
    message.append(((i * 13 + 17) % 256))
  // Session ID length: 32
