  // Selected cipher suite: TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384
  message.append(0x00)
  message.append(0x9D)
  // Compression method: null
  message.append(0)
  message

// TLS Handshake: Certificate Message
fn generateCertificateMessage(cert: TlsCertificate) -> array<number>
  let message = []
  // Handshake Type: Certificate (11)
  message.append(11)
  // Certificate chain length (1 cert): 3 bytes length + cert data
  message.append(0x00)
  message.append(0x00)
  message.append(0x03)
  // Single certificate length: 3 bytes (simplified 100 bytes)
  message.append(0x00)
  message.append(0x00)
  message.append(100)
