    "roles": [],
    "permissions": []
  }

// Validate JWT token
fn validateJwt(
  tokenString: string,
  config: AuthConfig
) -> Result<JwtToken, string>
  // Parse JWT
  let parseResult = parseJwt(tokenString)
  match parseResult
    Ok(token) ->
      // Verify signature
      if !verifyJwtSignature(tokenString, config)
        return Err("Invalid signature")

      // Verify claims
      if !verifyJwtClaims(token, config["audience"])
        return Err("Invalid claims")

      Ok(token)
    Err(e) ->
      Err(e)

// Refresh JWT token
fn refreshJwt(
  token: JwtToken,
  config: AuthConfig
) -> Result<JwtToken, string>
  let payload = token["payload"]

  // Check if refresh is still valid (within refresh window)
  let now = getCurrentTimeSeconds()
  let issuedAt = payload["iat"]
  let refreshWindow = config["refreshExpiry"]

  if (now - issuedAt) > refreshWindow
    return Err("Refresh token expired")

  // Generate new token with same user
  let newToken = generateJwt(
    payload["sub"],
    "",  // username not in payload
    config,
    payload["roles"],
    payload["permissions"]
  )

  Ok(newToken)

